// Point this at your deployed pancity-backend, e.g.
// "https://xxxx-3000.csb.app/api". Until it's set, signup/login will show
// a clear error instead of silently letting anyone into the app.
const API_BASE =
  (typeof process !== "undefined" && process.env && process.env.REACT_APP_API_BASE) ||
  "https://pancity-backend.onrender.com/api";

// Kept in module scope (not React state) so any component/helper in this
// file can attach it to a request without prop-drilling a token through
// dozens of components. Cleared on logout.
let userAuthToken = null;
function setUserAuthToken(token) {
  userAuthToken = token;
}

// Short-lived token returned by the backend after a successful PIN-based
// purchase — lets a fingerprint-unlocked purchase skip re-typing the PIN
// for 5 minutes, same rule the backend enforces server-side.
let quickAuthToken = null;
function setQuickAuthToken(token) {
  quickAuthToken = token || null;
}

async function apiFetch(path, { method = "GET", body, auth = true } = {}) {
  if (!API_BASE) {
    throw new Error(
      "Backend not configured yet — set REACT_APP_API_BASE to your pancity-backend URL."
    );
  }
  const headers = { "Content-Type": "application/json" };
  if (auth && userAuthToken) headers.Authorization = `Bearer ${userAuthToken}`;
  const res = await fetch(`${API_BASE}${path}`, {
    method,
    headers,
    body: body !== undefined ? JSON.stringify(body) : undefined,
  });
  let data = null;
  try {
    data = await res.json();
  } catch (e) {
    // No JSON body (e.g. 204) — leave data as null.
  }
  if (!res.ok) {
    throw new Error((data && (data.message || data.error)) || `Request failed (${res.status})`);
  }
  return data;
}
const pancityLogo = "data:image/png;base64,";

// Converts the backend's VAPID public key (base64url string) into the
// Uint8Array format the Push API requires.
function urlBase64ToUint8Array(base64String) {
  const padding = "=".repeat((4 - (base64String.length % 4)) % 4);
  const base64 = (base64String + padding).replace(/-/g, "+").replace(/_/g, "/");
  const rawData = atob(base64);
  const outputArray = new Uint8Array(rawData.length);
  for (let i = 0; i < rawData.length; i++) {
    outputArray[i] = rawData.charCodeAt(i);
  }
  return outputArray;
}

// Registers /sw.js (if not already registered), asks for notification
// permission, subscribes this device to real Web Push using the backend's
// VAPID public key, then hands the subscription to the backend so it can
// actually deliver a push — including while Pancity is closed or the
// phone is locked, not just an in-tab Notification like before.
async function registerPushSubscription() {
  if (
    typeof window === "undefined" ||
    !("serviceWorker" in navigator) ||
    !("PushManager" in window)
  ) {
    return { ok: false, reason: "unsupported" };
  }
  try {
    let permission = Notification.permission;
    if (permission === "default") {
      permission = await Notification.requestPermission();
    }
    if (permission !== "granted") {
      return { ok: false, reason: "denied" };
    }
    const registration = await navigator.serviceWorker.register("/sw.js");
    await navigator.serviceWorker.ready;
    let subscription = await registration.pushManager.getSubscription();
    if (!subscription) {
      const { publicKey } = await apiFetch("/notifications/vapid-public-key", { auth: false });
      subscription = await registration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(publicKey),
      });
    }
    await apiFetch("/notifications/subscribe", {
      method: "POST",
      body: subscription.toJSON(),
    });
    return { ok: true };
  } catch (err) {
    return { ok: false, reason: err.message || "declined" };
  }
}

// Tells the backend to stop pushing to this device, then tears down the
// local subscription so the browser stops holding onto it too.
async function unregisterPushSubscription() {
  try {
    if (!("serviceWorker" in navigator)) return { ok: true };
    const registration = await navigator.serviceWorker.getRegistration();
    const subscription = registration && (await registration.pushManager.getSubscription());
    if (subscription) {
      await apiFetch("/notifications/unsubscribe", {
        method: "POST",
        body: { endpoint: subscription.endpoint },
      }).catch(() => {});
      await subscription.unsubscribe();
    }
    return { ok: true };
  } catch (err) {
    return { ok: false, reason: err.message };
  }
}

