function detectNetwork(phone) {
  let p = (phone || "").replace(/\s/g, "");
  if (p.startsWith("+234")) p = "0" + p.slice(4);
  else if (p.startsWith("234")) p = "0" + p.slice(3);
  const prefix = p.slice(0, 4);
  for (const [network, prefixes] of Object.entries(NETWORK_PREFIXES)) {
    if (prefixes.includes(prefix)) return network;
  }
  return null;
}

// Converts an ArrayBuffer/TypedArray to a base64url string for sending
// WebAuthn binary fields to the backend over JSON.
function bufferToBase64url(buffer) {
  const bytes = new Uint8Array(buffer);
  let str = "";
  for (let i = 0; i < bytes.byteLength; i++) str += String.fromCharCode(bytes[i]);
  return btoa(str).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
}

// Reverses bufferToBase64url — turns a base64url string from the backend
// back into an ArrayBuffer the WebAuthn API can use (challenge, user.id, etc.).
function base64urlToBuffer(base64url) {
  const base64 = base64url.replace(/-/g, "+").replace(/_/g, "/");
  const padded = base64 + "=".repeat((4 - (base64.length % 4)) % 4);
  const str = atob(padded);
  const bytes = new Uint8Array(str.length);
  for (let i = 0; i < str.length; i++) bytes[i] = str.charCodeAt(i);
  return bytes.buffer;
}

// Registers a real passkey for the currently signed-in user: fetches
// creation options from the backend (server generates the challenge and
// knows who the user is from the auth token), runs the actual WebAuthn
// ceremony, then sends the resulting credential back for the backend to
// verify and store against the account.
async function registerBiometricCredential() {
  if (
    typeof window === "undefined" ||
    !window.PublicKeyCredential ||
    !navigator.credentials
  ) {
    return { ok: false, reason: "unsupported" };
  }
  try {
    const options = await apiFetch("/auth/webauthn/register-options");
    const publicKey = {
      ...options,
      challenge: base64urlToBuffer(options.challenge),
      user: { ...options.user, id: base64urlToBuffer(options.user.id) },
      excludeCredentials: (options.excludeCredentials || []).map((c) => ({
        ...c,
        id: base64urlToBuffer(c.id),
      })),
    };
    const credential = await navigator.credentials.create({ publicKey });
    await apiFetch("/auth/webauthn/register-verify", {
      method: "POST",
      body: {
        id: credential.id,
        rawId: bufferToBase64url(credential.rawId),
        type: credential.type,
        response: {
          attestationObject: bufferToBase64url(credential.response.attestationObject),
          clientDataJSON: bufferToBase64url(credential.response.clientDataJSON),
        },
      },
    });
    return { ok: true };
  } catch (err) {
    return { ok: false, reason: err.message || "declined" };
  }
}

// Logs a returning user in with a previously registered passkey — no
// email/password typed at all. The backend issues a challenge, we run the
// WebAuthn "get assertion" ceremony, then the backend verifies the
// signature against the stored public key and tells us who signed in.
async function loginWithBiometricPasskey() {
  if (
    typeof window === "undefined" ||
    !window.PublicKeyCredential ||
    !navigator.credentials
  ) {
    return { ok: false, reason: "unsupported" };
  }
  try {
    const options = await apiFetch("/auth/webauthn/login-options", {
      method: "POST",
      auth: false,
      body: {},
    });
    const publicKey = {
      ...options,
      challenge: base64urlToBuffer(options.challenge),
      allowCredentials: (options.allowCredentials || []).map((c) => ({
        ...c,
        id: base64urlToBuffer(c.id),
      })),
    };
    const assertion = await navigator.credentials.get({ publicKey });
    const data = await apiFetch("/auth/webauthn/login-verify", {
      method: "POST",
      auth: false,
      body: {
        id: assertion.id,
        rawId: bufferToBase64url(assertion.rawId),
        type: assertion.type,
        response: {
          authenticatorData: bufferToBase64url(assertion.response.authenticatorData),
          clientDataJSON: bufferToBase64url(assertion.response.clientDataJSON),
          signature: bufferToBase64url(assertion.response.signature),
          userHandle: assertion.response.userHandle
            ? bufferToBase64url(assertion.response.userHandle)
            : null,
        },
      },
    });
    return { ok: true, data };
  } catch (err) {
    return { ok: false, reason: err.message || "declined" };
  }
}

// Attempts to trigger the device's real fingerprint/Face ID prompt via WebAuthn.
// Returns "success" if the user verifies, "declined" if they cancel/fail verification,
// or "unsupported" if this device/browser can't do platform biometrics (e.g. desktop
// without Touch ID/Windows Hello, or an unsupported/sandboxed browser context).
// Used only as a local device-presence gate for actions where identity was
// already established another way (app-lock unlock, confirming a purchase
// with a fresh quickAuthToken) — for actually signing a person in, use
// loginWithBiometricPasskey above instead, which the backend verifies.
async function tryDeviceBiometric() {
  try {
    if (
      typeof window === "undefined" ||
      !window.PublicKeyCredential ||
      !navigator.credentials ||
      !PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable
    ) {
      return "unsupported";
    }

    const available = await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable();
    if (!available) return "unsupported";

    const challenge = new Uint8Array(32);
    window.crypto.getRandomValues(challenge);
    const userId = new Uint8Array(16);
    window.crypto.getRandomValues(userId);

    await navigator.credentials.create({
      publicKey: {
        challenge,
        rp: { name: "Pancity" },
        user: { id: userId, name: "pancity-user", displayName: "Pancity User" },
        pubKeyCredParams: [
          { type: "public-key", alg: -7 },
          { type: "public-key", alg: -257 },
        ],
        authenticatorSelection: { authenticatorAttachment: "platform", userVerification: "required" },
        timeout: 60000,
        attestation: "none",
      },
    });
    return "success";
  } catch (err) {
    return "declined";
  }
}

