function getPlanPrice(basePrice, tierId) {
  const tier = ACCOUNT_TIERS.find((t) => t.id === tierId) || ACCOUNT_TIERS[0];
  return Math.round(basePrice * (1 - tier.discount));
}

// Data bundles + prices are entirely admin-managed — there is nothing
// hardcoded here. The real list comes from GET /plans?category=data and is
// loaded into the `dataPlans` state below; until the admin has added at
// least one plan there, "AVAILABLE BUNDLES" will correctly show nothing.

// All services now go through the real backend's POST /transactions/purchase
// — the old local-only simulation for Cable TV / Electricity / Exam Pin has
// been removed now that every service type is wired.

const TX_META = {
  "Mobile Data": { title: "Data", icon: Wifi },
  Airtime: { title: "Airtime", icon: Smartphone },
  "Cable TV": { title: "Cable TV", icon: Tv },
  "Airtime 2 Cash": { title: "Airtime2Cash", icon: ArrowLeftRight },
  Electricity: { title: "Electricity", icon: Zap },
  "Exam Pin": { title: "Exam Pin", icon: FileText },
};

// Builds the payload the backend's POST /transactions/purchase endpoint
// expects, from whichever fields that service's form collected.
function buildPurchasePayload(service, form, amount) {
  switch (service) {
    case "Mobile Data":
      return { type: "data", network: form.network || "", target: form.phone || "", planName: form.plan || undefined };
    case "Airtime":
      return { type: "airtime", network: form.network || "", target: form.phone || "" };
    case "Cable TV":
      return { type: "cable", network: form.cableProvider || "", target: form.smartcard || "", planName: form.package || undefined };
    case "Electricity":
      return { type: "electricity", network: form.disco || "", target: form.meter || "" };
    case "Exam Pin":
      return { type: "exam-pin", network: form.examType || "", target: String(form.quantity || 1) };
    case "Airtime 2 Cash":
      return {
        type: "airtime2cash",
        network: form.network || "",
        target: form.phone || "",
        payoutBankName: form.bankName || undefined,
        payoutAccountNumber: form.accountNumber || undefined,
      };
    default:
      return { type: "airtime", network: form.network || "", target: form.phone || "" };
  }
}

function getTxDescription(service, form) {
  switch (service) {
    case "Mobile Data":
      return `Data sent to ${form.phone || ""}`;
    case "Airtime":
      return `${(form.network || "").toLowerCase()} airtime to ${form.phone || ""}`;
    case "Cable TV":
      return `${form.cableProvider || ""} sub for ${form.smartcard || ""}`;
    case "Electricity":
      return `${form.disco || ""} bill for meter ${form.meter || ""}`;
    case "Exam Pin":
      return `${form.examType || ""} pin x${form.quantity || 1}`;
    case "Airtime 2 Cash":
      return `${(form.network || "").toLowerCase()} airtime2cash - ${form.phone || ""}`;
    default:
      return service;
  }
}

